import React from 'react';
import SneakerItem from './SneakerItem';
import sneakersList from '../sneakersList';
import '../styles/SneakersGrid.css';

function SneakersList() {
  return (
    <div className="sneakers-container">
      <h1 className="sneakers-title">Collection Sneakers</h1>
      <p className="sneakers-subtitle">
        Découvrez notre sélection de sneakers tendance avec des avis authentiques
      </p>
      
      <div className="sneakers-grid">
        {sneakersList.map((sneaker) => (
          <SneakerItem
            key={sneaker.id}
            nom={sneaker.nom}
            marque={sneaker.marque}
            prix={sneaker.prix}
            style={sneaker.style}
            esthetique={sneaker.esthetique}
            confort={sneaker.confort}
          />
        ))}
      </div>
    </div>
  );
}

export default SneakersList;
